import { test, expect } from '@playwright/test';

const BASE_URL = process.env.BASE_URL ?? 'http://localhost:3000';

test.describe('Health API - Happy Path', () => {
  test.beforeEach(async ({ request }) => {
    // Shared setup for health endpoint tests
  });

  // SCENARIO_ID: c8a33bbc-bde7-4e59-a14c-d37057e20c93
  test('Health check returns ok when all dependencies are healthy', async ({ request }) => {
    const response = await request.get(`${BASE_URL}/api/health`);

    expect(response.status()).toBe(200);

    const body = await response.json();
    expect(body.status).toBe('ok');
    expect(body.ollama).toBe(true);
    expect(body.chromadb).toBe(true);
    expect(body).toHaveProperty('llm_model');
    expect(typeof body.llm_model).toBe('string');
    expect(body.llm_model.length).toBeGreaterThan(0);
  });

  // SCENARIO_ID: fc3758b7-f7dc-4e2b-aea4-b5f263bf9925
  test('Health check verifies Ollama endpoint URL is correctly constructed', async ({ request }) => {
    const response = await request.get(`${BASE_URL}/api/health`);

    expect(response.status()).toBe(200);

    const body = await response.json();
    // If ollama is reachable, the URL was constructed correctly
    expect(body).toHaveProperty('ollama');
    expect(body).toHaveProperty('llm_model');
  });
});

