test.describe('Health API - Edge Case', () => {
  // SCENARIO_ID: e329141a-7c43-45b8-a8a0-7ecae320f12a
  test('Health check handles both dependencies failing simultaneously', async ({ request }) => {
    // Note: This test requires both Ollama and ChromaDB to be unavailable
    // Run with all services stopped
    const response = await request.get(`${BASE_URL}/api/health`);

    expect(response.status()).toBe(200);

    const body = await response.json();
    expect(body.status).toBe('degraded');
    expect(body.ollama).toBe(false);
    expect(body.chromadb).toBe(false);
  });

  // SCENARIO_ID: 5256fc97-0693-46aa-b5e5-b23c9afce6dc
  test('Health check handles Ollama timeout correctly', async ({ request }) => {
    // Note: This test requires Ollama to respond slowly (>3 seconds)
    // The health endpoint has a 3-second timeout for Ollama requests
    const startTime = Date.now();
    const response = await request.get(`${BASE_URL}/api/health`);
    const responseTime = Date.now() - startTime;

    expect(response.status()).toBe(200);
    // Total response time should be reasonable even with timeout
    expect(responseTime).toBeLessThan(5000);

    const body = await response.json();
    expect(body).toHaveProperty('ollama');
    // If timeout occurred, ollama should be false
    expect(typeof body.ollama).toBe('boolean');
  });

  // SCENARIO_ID: fdfe7e0f-0289-4c06-8072-4f3ead738f31
  test('Concurrent health check requests do not cause race conditions', async ({ request }) => {
    const concurrentRequestCount = 10;
    const requests = Array(concurrentRequestCount)
      .fill(null)
      .map(() => request.get(`${BASE_URL}/api/health`));

    const responses = await Promise.all(requests);

    // All requests should return 200
    for (const response of responses) {
      expect(response.status()).toBe(200);
    }

    const bodies = await Promise.all(responses.map((r) => r.json()));

    // All responses should have consistent structure
    const requiredFields = ['status', 'ollama', 'chromadb', 'llm_model'];
    for (const body of bodies) {
      for (const field of requiredFields) {
        expect(body).toHaveProperty(field);
      }
    }

    // All responses should have identical values (no race conditions)
    const firstBody = bodies[0];
    for (const body of bodies) {
      expect(body.status).toBe(firstBody.status);
      expect(body.ollama).toBe(firstBody.ollama);
      expect(body.chromadb).toBe(firstBody.chromadb);
    }
  });
});

test.describe('Health API - Security', () => {
  // SCENARIO_ID: f0de2f0c-eb57-4ea0-92be-593b39671534
  test('Health endpoint is accessible without authentication', async ({ request }) => {
    // Explicitly send request without any auth headers
    const response = await request.get(`${BASE_URL}/api/health`, {
      headers: {
        // No Authorization, X-API-Key, or other auth headers
        'Accept': 'application/json',
      },
    });

    // Health endpoint should be publicly accessible for Kubernetes probes
    expect(response.status()).toBe(200);

    const body = await response.json();
    expect(body).toHaveProperty('status');
    expect(['ok', 'degraded']).toContain(body.status);
  });

  // SCENARIO_ID: 599d8ec7-aee5-4b84-adfe-282219ff4836
  test('Health endpoint does not expose sensitive configuration data', async ({ request }) => {
    const response = await request.get(`${BASE_URL}/api/health`);

    expect(response.status()).toBe(200);

    const body = await response.json();
    const bodyKeys = Object.keys(body);

    // Only these fields should be present in the response
    const allowedFields = ['status', 'ollama', 'chromadb', 'llm_model'];
    for (const key of bodyKeys) {
      expect(allowedFields).toContain(key);
    }

    // Response should not contain sensitive keywords in any string value
    const bodyString = JSON.stringify(body).toLowerCase();
    const sensitiveKeywords = ['password', 'secret', 'api_key', 'apikey', 'token', 'credential', 'private'];
    for (const keyword of sensitiveKeywords) {
      expect(bodyString).not.toContain(keyword);
    }

    // Verify no additional nested objects with sensitive data
    for (const key of bodyKeys) {
      expect(typeof body[key]).not.toBe('object');
    }
  });
});
